+
+            let cond = numpy
+                .getattr("array")?
+                .call1((PyList::new(py, [true, false])?,))?;
+            let data = numpy
+                .getattr("array")?
+                .call1((PyList::new(py, [1_i64, 2, 3])?,))?;
+
+            let ours = masked_where_fn
+                .call1((cond.clone(), data.clone()))
+                .expect_err("masked_where shape mismatch must error");
